INSERT IGNORE INTO ai_syllabus_topics(discipline_name,course_number,topic_code,title,keywords) SELECT DISTINCT discipline_name, COALESCE(course_number,3), CONCAT('T',topic_id), CONCAT('Тема ',topic_id), CONCAT(discipline_name, ', ', topic_id) FROM raw_exam_results WHERE topic_id IS NOT NULL;
INSERT IGNORE INTO hier_questions(question_id,syllabus_topic_id,question_text,question_type,max_score) SELECT q.question_id, st.syllabus_topic_id, COALESCE(q.question_text, CONCAT('Вопрос ',q.question_id)), 'exam', 100 FROM questions q LEFT JOIN disciplines d ON d.discipline_id=q.discipline_id LEFT JOIN ai_syllabus_topics st ON st.discipline_name=d.discipline_name AND st.topic_code=CONCAT('T',q.topic_id);
INSERT IGNORE INTO semantic_analysis(question_id,syllabus_topic_id,tfidf_score,match_status) SELECT question_id, syllabus_topic_id, ROUND(0.55 + RAND()*0.4, 4), IF(RAND()>0.2,'match','weak') FROM hier_questions;
INSERT IGNORE INTO rule_classifiers(rule_id,rule_name,rule_order,is_active) VALUES (1,'Слишком сложный вопрос',10,1),(2,'Слишком простой вопрос',20,1),(3,'Нестабильность после апелляции',30,1);
INSERT IGNORE INTO ai_settings(setting_key,setting_value,setting_category) VALUES ('quality.easy_threshold','85','quality'),('quality.hard_threshold','60','quality'),('semantic.min_match','0.55','semantic');